//! # Rust Emitter
//!
//! Core transpilation from TypeScript to Rust source.

use crate::{parser::SourceFile, analyzer::AnalysisResult};
use crate::codegen::{GeneratedModule, Import, ImportedName, CodegenOptions};
use super::emitters::TypeEmitter;

/// Options for code emission.
#[derive(Debug, Clone, Default)]
pub struct EmitOptions {
    pub source_map: bool,
    pub pretty: bool,
}

/// Emits Rust code from TypeScript source.
pub struct RustEmitter<'a> {
    source: &'a SourceFile,
    analysis: &'a AnalysisResult,
    imports: Vec<Import>,
    output: String,
    indent: usize,
    type_emitter: TypeEmitter,
    options: CodegenOptions,
}

impl<'a> RustEmitter<'a> {
    /// Create a new emitter.
    pub fn new(source: &'a SourceFile, analysis: &'a AnalysisResult) -> Self {
        Self {
            source,
            analysis,
            imports: Vec::new(),
            output: String::new(),
            indent: 0,
            type_emitter: TypeEmitter::new(),
            options: CodegenOptions::default(),
        }
    }

    /// Emit the complete module.
    pub fn emit(mut self) -> crate::Result<GeneratedModule> {
        self.write_header();
        self.write_types();
        self.write_functions();
        self.write_footer();

        let name = self.source.path.file_stem()
            .and_then(|s| s.to_str())
            .unwrap_or("module")
            .to_string();

        Ok(GeneratedModule {
            name,
            source: self.output,
            imports: self.imports,
            types: Vec::new(),
            functions: Vec::new(),
        })
    }

    /// Write module header.
    fn write_header(&mut self) {
        self.push_line("//! Generated from Rune source");
        self.push_line("");
        self.push_line("use std::collections::HashMap;");
        self.push_line("use std::fmt::{self, Write};");
        self.push_line("");

        // Add protocol imports for the app crate
        if self.source.path.to_string_lossy().contains("/app/src/") {
            self.push_line("use protocol::{AppState, Filter, Task};");
            self.push_line("");
        }
    }

    /// Write type definitions.
    fn write_types(&mut self) {
        for (name, info) in self.analysis.types.iter() {
            match info {
                crate::analyzer::TypeInfo::Struct(s) => {
                    self.push_line("");
                    self.push_line(&s.to_rust());
                    self.push_line("");
                }
                crate::analyzer::TypeInfo::Enum(e) => {
                    self.push_line("");
                    self.push_line(&e.to_rust());
                    self.push_line("");
                }
                _ => {}
            }
        }
    }

    /// Write function definitions.
    fn write_functions(&mut self) {
        for (name, info) in self.analysis.types.iter() {
            if let crate::analyzer::TypeInfo::Function(func) = info {
                self.emit_function(name, func);
            }
        }
    }

    /// Emit a single function.
    fn emit_function(&mut self, name: &str, func: &crate::analyzer::FunctionInfo) {
        let rust_name = to_snake_case(name);
        let async_prefix = if func.is_async { "async " } else { "" };

        // Build parameter list
        let params: Vec<String> = func.params.iter()
            .map(|(n, t)| format!("{}: {}", to_snake_case(n), t.to_rust_type()))
            .collect();
        let params_str = params.join(", ");

        // Build return type
        let return_type = func.return_type.to_rust_type();

        self.push_line("");
        self.push_line(&format!("/// Function: {}", name));

        if func.is_async {
            self.push_line(&format!("{}pub fn {}({}) -> impl Future<Output = {}> + '_ {{", async_prefix, rust_name, params_str, return_type));
        } else {
            self.push_line(&format!("pub fn {}({}) -> {} {{", rust_name, params_str, return_type));
        }

        self.indent += 1;

        // Generate function body based on the source
        self.generate_function_body(name);

        self.indent -= 1;
        self.push_line("}");
        self.push_line("");
    }

    /// Generate function body from source.
    fn generate_function_body(&mut self, name: &str) {
        // Find the function in the source text
        let source = &self.source.source;

        for line in source.lines() {
            let trimmed = line.trim();

            // Skip empty lines and comments
            if trimmed.is_empty() || trimmed.starts_with("//") {
                self.push_line("");
                continue;
            }

            // Find function body
            if trimmed.contains("function ") && trimmed.contains(name) {
                let body_start = trimmed.find('{').or_else(|| trimmed.find("=>"));
                if let Some(start) = body_start {
                    let body = &trimmed[start + 1..];
                    if body.contains('}') {
                        self.translate_line(&format!("    {}", body.trim_end_matches('}').trim_start_matches('{')));
                    }
                }
            }
        }
    }

    /// Translate a TypeScript line to Rust.
    fn translate_line(&mut self, line: &str) {
        let trimmed = line.trim();

        if trimmed.is_empty() {
            self.push_line("");
            return;
        }

        // Variable declarations
        if trimmed.starts_with("const ") || trimmed.starts_with("let ") {
            self.translate_binding(trimmed);
            return;
        }

        // Return statements
        if trimmed.starts_with("return ") {
            let expr = trimmed.strip_prefix("return ").unwrap().trim_end_matches(';');
            self.push_indent();
            self.push_line(&format!("return {};", self.translate_expr(expr)));
            return;
        }

        // If statements
        if trimmed.starts_with("if ") {
            self.translate_if(trimmed);
            return;
        }

        // For loops
        if trimmed.starts_with("for ") {
            self.translate_for(trimmed);
            return;
        }

        // Switch statements
        if trimmed.starts_with("switch ") {
            self.translate_switch(trimmed);
            return;
        }

        // While loops
        if trimmed.starts_with("while ") {
            self.translate_while(trimmed);
            return;
        }

        // Function calls (likely in expression context)
        self.push_indent();
        self.push_line(&format!("{};", self.translate_expr(trimmed.trim_end_matches(';'))));
    }

    /// Translate a variable binding.
    fn translate_binding(&mut self, line: &str) {
        let (keyword, rest) = if line.starts_with("const ") {
            ("let".to_string(), line.strip_prefix("const ").unwrap())
        } else {
            ("let mut".to_string(), line.strip_prefix("let ").unwrap())
        };

        // Pattern: name: type = value
        let rest = rest.trim_end_matches(';');

        if let Some(eq_pos) = rest.find(" = ") {
            let name_type = &rest[..eq_pos];
            let value = &rest[eq_pos + 3..];

            if let Some(colon_pos) = name_type.find(": ") {
                let name = name_type[..colon_pos].trim();
                let type_hint = name_type[colon_pos + 2..].trim();
                self.push_indent();
                self.push_line(&format!("{} {}: {} = {};", keyword, name, self.type_emitter.emit_type(&self.parse_type_hint(type_hint)), self.translate_expr(value)));
            } else {
                let name = name_type.trim();
                self.push_indent();
                self.push_line(&format!("{} {} = {};", keyword, name, self.translate_expr(value)));
            }
        }
    }

    /// Translate an if statement.
    fn translate_if(&mut self, line: &str) {
        let rest = line.strip_prefix("if ").unwrap();

        if let Some(brace_pos) = rest.find('{') {
            let condition = rest[..brace_pos].trim();
            self.push_indent();
            self.push_line(&format!("if {} {{", self.translate_condition(condition)));
            self.indent += 1;
        }
    }

    /// Translate a for loop.
    fn translate_for(&mut self, line: &str) {
        // for (const item of array) or for (let i = 0; i < len; i++)
        if line.contains(" of ") {
            // Iterator-based for loop
            if let Some(of_pos) = line.find(" of ") {
                let binding = &line[5..of_pos].trim();
                let array = &line[of_pos + 4..].trim().trim_end_matches(')').trim_end_matches(';');

                let var_name = binding.replace("const ", "").replace("let ", "").trim().to_string();
                self.push_indent();
                self.push_line(&format!("for {} in {} {{", var_name, self.translate_expr(array)));
                self.indent += 1;
            }
        } else if line.contains(" = ") {
            // C-style for loop
            let rest = line.strip_prefix("for ").unwrap().trim_start_matches('(').trim_end_matches(')');
            self.push_indent();
            self.push_line(&format!("for {} {{", self.translate_expr(rest.trim_end_matches(';'))));
            self.indent += 1;
        }
    }

    /// Translate a switch statement.
    fn translate_switch(&mut self, line: &str) {
        let rest = line.strip_prefix("switch ").unwrap();
        if let Some(brace_pos) = rest.find('{') {
            let expr = rest[..brace_pos].trim();
            self.push_indent();
            self.push_line(&format!("match {} {{", self.translate_expr(expr)));
            self.indent += 1;
        }
    }

    /// Translate a while loop.
    fn translate_while(&mut self, line: &str) {
        let rest = line.strip_prefix("while ").unwrap();
        if let Some(brace_pos) = rest.find('{') {
            let condition = rest[..brace_pos].trim();
            self.push_indent();
            self.push_line(&format!("while {} {{", self.translate_condition(condition)));
            self.indent += 1;
        }
    }

    /// Translate an expression.
    fn translate_expr(&self, expr: &str) -> String {
        let expr = expr.trim();

        // String literals
        if expr.starts_with('"') || expr.starts_with('\'') {
            return expr.to_string();
        }

        // Number literals
        if expr.parse::<f64>().is_ok() {
            return expr.to_string();
        }

        // Boolean literals
        if expr == "true" || expr == "false" {
            return expr.to_string();
        }

        // Ternary operator
        if expr.contains(" ? ") {
            return self.translate_ternary(expr);
        }

        // Binary operations
        if let Some(op) = self.find_binary_op(expr) {
            return self.translate_binary_op(expr, op);
        }

        // Function calls
        if expr.contains('(') {
            return self.translate_call(expr);
        }

        // Property access
        if expr.contains('.') && !expr.contains('(') {
            return self.translate_property_access(expr);
        }

        // Array literals
        if expr.starts_with('[') {
            return self.translate_array_literal(expr);
        }

        // Object literals
        if expr.starts_with('{') {
            return self.translate_object_literal(expr);
        }

        // Simple identifier
        to_snake_case(expr)
    }

    /// Translate a ternary expression.
    fn translate_ternary(&self, expr: &str) -> String {
        // Find the ? and : positions
        let question_pos = expr.find(" ? ").unwrap_or(expr.find("?(").unwrap_or(0));
        let colon_pos = expr.rfind(" : ").unwrap_or(expr.rfind(":(").unwrap_or(0));

        if colon_pos > question_pos {
            let condition = self.translate_condition(&expr[..question_pos]);
            let then_expr = expr[question_pos + 3..colon_pos].trim();
            let else_expr = expr[colon_pos + 3..].trim_end_matches(';').trim_end_matches(')');
            return format!("if {} {{ {} }} else {{ {} }}",
                condition,
                self.translate_expr(then_expr),
                self.translate_expr(else_expr)
            );
        }

        expr.to_string()
    }

    /// Translate a binary operation.
    fn find_binary_op(&self, expr: &str) -> Option<&'static str> {
        let ops = ["+=", "-=", "*=", "/=", "===", "!==", "==", "!=", "<=", ">=", "&&", "||", "+", "-", "*", "/", "%", ">", "<", "|", "&", "^"];

        for op in ops {
            if expr.contains(op) {
                return Some(op);
            }
        }
        None
    }

    /// Translate a binary operation.
    fn translate_binary_op(&self, expr: &str, op: &str) -> String {
        let parts: Vec<&str> = expr.split(op).collect();
        if parts.len() == 2 {
            let left = parts[0].trim();
            let right = parts[1].trim();

            let rust_op = match op {
                "===" | "==" => "==",
                "!==" | "!=" => "!=",
                "&&" => "&&",
                "||" => "||",
                "+" => "+",
                "-" => "-",
                "*" => "*",
                "/" => "/",
                "%" => "%",
                "<" => "<",
                ">" => ">",
                "<=" => "<=",
                ">=" => ">=",
                "|" => "|",
                "&" => "&",
                "^" => "^",
                _ => op,
            };

            return format!("({} {} {})", self.translate_expr(left), rust_op, self.translate_expr(right));
        }

        expr.to_string()
    }

    /// Translate a function call.
    fn translate_call(&self, expr: &str) -> String {
        if let Some(paren_pos) = expr.find('(') {
            let func = &expr[..paren_pos];
            let args = &expr[paren_pos + 1..].trim_end_matches(')').trim_end_matches(';');

            let rust_func = to_snake_case(func);
            let translated_args: Vec<String> = args.split(',')
                .map(|a| self.translate_expr(a.trim()))
                .collect();

            return format!("{}({})", rust_func, translated_args.join(", "));
        }

        to_snake_case(expr)
    }

    /// Translate property access.
    fn translate_property_access(&self, expr: &str) -> String {
        let parts: Vec<&str> = expr.split('.').collect();
        parts.iter()
            .map(|p| to_snake_case(p))
            .collect::<Vec<_>>()
            .join(".")
    }

    /// Translate an array literal.
    fn translate_array_literal(&self, expr: &str) -> String {
        let inner = expr.trim_start_matches('[').trim_end_matches(']');
        let elements: Vec<String> = inner.split(',')
            .map(|e| self.translate_expr(e.trim()))
            .collect();

        format!("vec![{}]", elements.join(", "))
    }

    /// Translate an object literal.
    fn translate_object_literal(&self, expr: &str) -> String {
        let inner = expr.trim_start_matches('{').trim_end_matches('}');
        let fields: Vec<String> = inner.split(',')
            .filter_map(|f| {
                let f = f.trim();
                if f.is_empty() {
                    return None;
                }
                let parts: Vec<&str> = f.split(':').collect();
                if parts.len() == 2 {
                    let key = parts[0].trim();
                    let value = self.translate_expr(parts[1].trim());
                    return Some(format!("{}: {}", key, value));
                }
                Some(f.to_string())
            })
            .collect();

        format!("{{ {} }}", fields.join(", "))
    }

    /// Translate a condition.
    fn translate_condition(&self, cond: &str) -> String {
        let cond = cond.trim();

        // Negation
        if cond.starts_with('!') {
            let inner = cond.strip_prefix('!').unwrap().trim();
            return format!("!{}", self.translate_condition(inner));
        }

        // Parentheses
        if cond.starts_with('(') && cond.ends_with(')') {
            let inner = &cond[1..cond.len() - 1];
            return format!("({})", self.translate_condition(inner));
        }

        self.translate_expr(cond)
    }

    /// Write module footer.
    fn write_footer(&mut self) {
        self.push_line("// End of generated code");
    }

    /// Parse a type hint string.
    fn parse_type_hint(&self, hint: &str) -> crate::analyzer::TypeInfo {
        match hint {
            "number" => crate::analyzer::TypeInfo::Float,
            "string" => crate::analyzer::TypeInfo::String,
            "boolean" => crate::analyzer::TypeInfo::Boolean,
            _ => crate::analyzer::TypeInfo::Unknown,
        }
    }

    fn push(&mut self, s: &str) {
        self.output.push_str(s);
    }

    fn push_line(&mut self, s: &str) {
        self.output.push_str(s);
        self.output.push('\n');
    }

    fn push_indent(&mut self) {
        for _ in 0..self.indent {
            self.output.push_str("    ");
        }
    }
}

/// Convert camelCase/snake_case to snake_case.
fn to_snake_case(s: &str) -> String {
    let mut result = String::new();
    let mut prev_was_upper = false;

    for c in s.chars() {
        if c.is_uppercase() {
            if !result.is_empty() && !prev_was_upper {
                result.push('_');
            }
            result.push(c.to_ascii_lowercase());
            prev_was_upper = true;
        } else {
            result.push(c);
            prev_was_upper = false;
        }
    }

    // Handle consecutive uppercase (e.g., "URLParser" -> "url_parser")
    let mut final_result = String::new();
    let chars: Vec<char> = result.chars().collect();

    for (i, c) in chars.iter().enumerate() {
        if i > 0 && i < chars.len() - 1 {
            if c.is_uppercase() && !chars[i - 1].is_uppercase() {
                final_result.push('_');
            } else if c.is_uppercase() && chars[i + 1].is_uppercase() {
                // keep as is
            } else if c.is_uppercase() {
                final_result.push('_');
            }
        }
        final_result.push(c.to_ascii_lowercase());
    }

    final_result
}

//! # Subset Validator
//!
//! Validates that TypeScript code uses only the zero-overhead subset.

mod rules;

use crate::parser::SourceFile;

/// Validation error with source location.
#[derive(Debug, Clone)]
pub struct ValidationError {
    pub location: String,
    pub message: String,
    pub code: &'static str,
}

impl std::fmt::Display for ValidationError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}: {}", self.location, self.message)
    }
}

/// Validates the zero-overhead TypeScript subset.
#[derive(Debug, Default)]
pub struct SubsetValidator {
    /// Current depth for complexity tracking
    complexity: usize,
}

impl SubsetValidator {
    /// Create a new validator.
    #[must_use]
    pub fn new() -> Self {
        Self { complexity: 0 }
    }

    /// Validate an entire source file.
    pub fn validate(&mut self, source: &SourceFile) -> Result<(), ValidationError> {
        let lines: Vec<&str> = source.source.lines().collect();

        for (line_num, line) in lines.iter().enumerate() {
            let line_num = line_num + 1;
            let trimmed = line.trim();

            // Skip empty lines and comments
            if trimmed.is_empty() || trimmed.starts_with("//") || trimmed.starts_with("/*") {
                continue;
            }

            // Check for forbidden patterns
            self.check_line(trimmed, line_num as u32, &source.path.display().to_string())?;
        }

        Ok(())
    }

    /// Check a single line for forbidden patterns.
    fn check_line(
        &mut self,
        line: &str,
        line_num: u32,
        file: &str,
    ) -> Result<(), ValidationError> {
        let location = format!("{}:{}:1", file, line_num);

        // Check for forbidden 'any' type
        if line.contains(": any") || line.ends_with("any") {
            return Err(ValidationError {
                location,
                message: "Type 'any' requires dynamic dispatch. Use concrete types.".to_string(),
                code: "no_any",
            });
        }

        // Check for 'unknown' type
        if line.contains(": unknown") {
            return Err(ValidationError {
                location,
                message: "Type 'unknown' requires dynamic dispatch. Use concrete types.".to_string(),
                code: "no_unknown",
            });
        }

        // Check for 'var' declarations
        if line.contains("var ") {
            return Err(ValidationError {
                location,
                message: "Use 'const' or 'let' instead of 'var'.".to_string(),
                code: "no_var",
            });
        }

        // Check for loose equality
        if line.contains(" == ") || line.ends_with("==") {
            return Err(ValidationError {
                location,
                message: "Use '===' for strict equality.".to_string(),
                code: "no_loose_equality",
            });
        }

        // Check for try/catch/throw
        if line.contains("try") || line.contains("catch") || line.contains("throw") {
            return Err(ValidationError {
                location,
                message: "Use Result<T,E> return pattern instead of try/catch/throw.".to_string(),
                code: "no_exceptions",
            });
        }

        // Check for class declarations
        if line.contains("class ") {
            return Err(ValidationError {
                location,
                message: "Classes and prototype inheritance are forbidden. Use plain objects and functions.".to_string(),
                code: "no_classes",
            });
        }

        // Check for 'this' keyword
        if line.contains("this.") || line == "this" {
            return Err(ValidationError {
                location,
                message: "Use plain functions instead of class methods with 'this'.".to_string(),
                code: "no_this",
            });
        }

        // Check for eval
        if line.contains("eval(") {
            return Err(ValidationError {
                location,
                message: "Dynamic scoping via eval() is forbidden.".to_string(),
                code: "no_eval",
            });
        }

        // Check for 'with' statement
        if line.starts_with("with ") {
            return Err(ValidationError {
                location,
                message: "Dynamic scoping via 'with' is forbidden.".to_string(),
                code: "no_with",
            });
        }

        // Check for typeof
        if line.contains("typeof ") {
            return Err(ValidationError {
                location,
                message: "Runtime type inspection via typeof is forbidden.".to_string(),
                code: "no_typeof",
            });
        }

        // Check for instanceof
        if line.contains(" instanceof ") {
            return Err(ValidationError {
                location,
                message: "Runtime type inspection via instanceof is forbidden.".to_string(),
                code: "no_instanceof",
            });
        }

        // Check for delete
        if line.contains("delete ") {
            return Err(ValidationError {
                location,
                message: "Use ownership and explicit drops instead of delete.".to_string(),
                code: "no_delete",
            });
        }

        // Check for dynamic property access (object[key])
        if line.contains("][") || line.contains("[key]") {
            return Err(ValidationError {
                location,
                message: "Use Map<K,V> for dynamic keys or arrays for fixed indices.".to_string(),
                code: "no_dynamic_access",
            });
        }

        // Check for implicit any (untyped parameters)
        if let Some(func_start) = line.find("function ") {
            let after_func = &line[func_start + 9..];
            if let Some(paren_start) = after_func.find('(') {
                let before_paren = &after_func[..paren_start];
                let params_start = after_func.find('(').map(|p| p + 1);
                let params_end = after_func.find(')');

                if let (Some(ps), Some(pe)) = (params_start, params_end) {
                    let params = &after_func[ps..pe];
                    // Check if any param lacks type annotation
                    for param in params.split(',') {
                        let param = param.trim();
                        if !param.is_empty() && !param.contains(':') {
                            // This is implicit any - flag as warning
                        }
                    }
                }
            }
        }

        Ok(())
    }
}

