//! # Ownership Analysis
//!
//! Infers Rust ownership patterns from TypeScript usage.

use super::{TypeMap, OwnershipAnalysis, TypeInfo};

/// Borrow mode for a binding.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum BorrowMode {
    /// Immutable borrow `&T`
    Shared,
    /// Mutable borrow `&mut T`
    Mut,
    /// Owned value `T`
    Owned,
    /// Unknown mode
    Unknown,
}

impl BorrowMode {
    /// Check if this mode allows mutation.
    #[must_use]
    pub fn is_mutable(&self) -> bool {
        matches!(self, BorrowMode::Mut | BorrowMode::Owned)
    }

    /// Combine two borrow modes.
    #[must_use]
    #[allow(clippy::similar_names)]
    pub fn combine(self, other: BorrowMode) -> BorrowMode {
        use BorrowMode::*;
        match (self, other) {
            (Unknown, m) | (m, Unknown) => m,
            (Shared, Shared) => Shared,
            (Mut, _) | (_, Mut) => Mut,
            (Owned, Owned) => Owned,
            (Shared, Owned) | (Owned, Shared) => Owned,
        }
    }

    /// Convert to Rust reference prefix.
    #[must_use]
    pub fn to_rust_prefix(&self) -> &'static str {
        match self {
            BorrowMode::Shared => "&",
            BorrowMode::Mut => "&mut ",
            BorrowMode::Owned => "",
            BorrowMode::Unknown => "&",
        }
    }
}

/// Analyzes ownership and borrowing patterns.
#[derive(Debug)]
pub struct OwnershipAnalyzer {
    /// Consumed values (moved)
    consumed: Vec<String>,
    /// Mutable references taken
    mut_refs: Vec<String>,
    /// Shared references taken
    shared_refs: Vec<String>,
}

impl OwnershipAnalyzer {
    /// Create a new ownership analyzer.
    #[must_use]
    pub fn new() -> Self {
        Self {
            consumed: Vec::new(),
            mut_refs: Vec::new(),
            shared_refs: Vec::new(),
        }
    }

    /// Analyze types and produce ownership information.
    #[must_use]
    pub fn analyze(&mut self, types: &TypeMap) -> OwnershipAnalysis {
        let mut ownership = OwnershipAnalysis::default();

        for (name, info) in types.iter() {
            let mode = self.infer_mode(name, info);
            ownership.set(name.to_string(), mode);
        }

        ownership
    }

    /// Infer borrow mode from type info and usage patterns.
    fn infer_mode(&self, _name: &str, info: &TypeInfo) -> BorrowMode {
        match info {
            // Functions that take &mut self are mutable
            TypeInfo::Function(_) => BorrowMode::Owned,
            // Strings are usually borrowed unless mutated
            TypeInfo::String | TypeInfo::StringLiteral(_) => BorrowMode::Shared,
            // Arrays can be borrowed or owned
            TypeInfo::Array(_) => BorrowMode::Owned,
            // Primitives are usually owned or small-copied
            TypeInfo::Integer(_) | TypeInfo::Float | TypeInfo::Boolean => BorrowMode::Owned,
            // Complex types are usually owned
            TypeInfo::Struct(_) | TypeInfo::Enum(_) => BorrowMode::Owned,
            // Options and Results are usually owned
            TypeInfo::Option(_) | TypeInfo::Result(_, _) => BorrowMode::Owned,
            // Unknown defaults to shared
            TypeInfo::Unknown => BorrowMode::Unknown,
            // Generics default to owned
            TypeInfo::Generic(_) => BorrowMode::Owned,
        }
    }

    /// Record that a value was consumed (moved).
    pub fn record_consume(&mut self, name: &str) {
        self.consumed.push(name.to_string());
    }

    /// Record that a mutable reference was taken.
    pub fn record_mut_ref(&mut self, name: &str) {
        self.mut_refs.push(name.to_string());
    }

    /// Record that a shared reference was taken.
    pub fn record_shared_ref(&mut self, name: &str) {
        self.shared_refs.push(name.to_string());
    }

    /// Check if a value was consumed (moved).
    #[must_use]
    pub fn was_consumed(&self, name: &str) -> bool {
        self.consumed.contains(&name.to_string())
    }
}

impl Default for OwnershipAnalyzer {
    fn default() -> Self {
        Self::new()
    }
}

//! # Dylib Watcher
//!
//! Watches for changes in the hot reload directory and signals the host.

use std::path::{Path, PathBuf};
use std::sync::mpsc;
use std::time::Duration;
use notify::{Watcher, RecommendedWatcher, RecursiveMode, Event, EventKind};
use super::ReloadResult;

/// Watches for dylib changes and notifies the host.
pub struct DylibWatcher {
    /// Watch directory
    watch_dir: PathBuf,
    /// Notify watcher
    watcher: RecommendedWatcher,
    /// Event receiver
    receiver: mpsc::Receiver<ReloadEvent>,
    /// Current dylib path
    current: Option<PathBuf>,
}

impl DylibWatcher {
    /// Create a new watcher.
    pub fn new(hot_dir: &Path) -> ReloadResult<Self> {
        let watch_dir = hot_dir.to_path_buf();
        let (tx, rx) = mpsc::channel();

        let watcher = notify::recommended_watcher(move |res: Result<Event, notify::Error>| {
            if let Ok(event) = res {
                if matches!(event.kind, EventKind::Create(_) | EventKind::Modify(_)) {
                    let _ = tx.send(ReloadEvent::Changed);
                }
            }
        })
        .map_err(|e| super::ReloadError::Library(e.to_string()))?;

        let mut watcher = watcher;
        watcher
            .watch(&watch_dir, RecursiveMode::NonRecursive)
            .map_err(|e| super::ReloadError::Library(e.to_string()))?;

        Ok(Self {
            watch_dir,
            watcher,
            receiver: rx,
            current: None,
        })
    }

    /// Poll for changes with timeout.
    #[must_use]
    pub fn poll(&mut self, timeout: Duration) -> Option<ReloadEvent> {
        match self.receiver.recv_timeout(timeout) {
            Ok(event) => Some(event),
            Err(mpsc::RecvTimeoutError::Timeout) => None,
            Err(mpsc::RecvTimeoutError::Disconnected) => Some(ReloadEvent::Disconnected),
        }
    }

    /// Check if the current dylib has changed.
    pub fn check_current(&mut self) -> ReloadResult<Option<PathBuf>> {
        let current_link = self.watch_dir.join(".current");

        if !current_link.exists() {
            return Ok(None);
        }

        let target = std::fs::read_link(&current_link)?;

        if self.current.as_ref() != Some(&target) {
            self.current = Some(target.clone());
            return Ok(Some(target));
        }

        Ok(None)
    }

    /// Get the current dylib path.
    #[must_use]
    pub fn current_path(&self) -> Option<&Path> {
        self.current.as_deref()
    }

    /// Unwatch and clean up.
    pub fn unwatch(mut self) {
        let _ = self.watcher.unwatch(&self.watch_dir);
    }
}

/// Events from the watcher.
#[derive(Debug, Clone)]
pub enum ReloadEvent {
    /// A new dylib is available
    Changed,
    /// The channel was disconnected
    Disconnected,
}

//! # Expression Emitter
//!
//! Emits Rust code from TypeScript expressions.

use crate::analyzer::AnalysisResult;

/// Emits Rust code for expressions.
pub struct ExprEmitter<'a> {
    /// Output buffer
    output: String,
    /// Current indentation
    indent: usize,
    /// Analysis result
    _analysis: &'a AnalysisResult,
}

impl<'a> ExprEmitter<'a> {
    /// Create a new expression emitter.
    pub fn new(analysis: &'a AnalysisResult) -> Self {
        Self {
            output: String::new(),
            indent: 0,
            _analysis: analysis,
        }
    }

    /// Emit an expression.
    #[allow(unused)]
    pub fn emit_expr(&mut self, expr: &str) -> String {
        self.emit_string(expr);
        self.output.clone()
    }

    /// Emit an expression string to output.
    fn emit_string(&mut self, expr: &str) {
        self.output.push_str(expr);
    }

    /// Get the output.
    #[must_use]
    pub fn into_output(self) -> String {
        self.output
    }
}

//! # Statement Emitter
//!
//! Emits Rust code from TypeScript statements.

use crate::analyzer::AnalysisResult;
use super::expr::ExprEmitter;

/// Emits Rust code for statements.
pub struct StmtEmitter<'a> {
    /// Output buffer
    output: String,
    /// Current indentation
    indent: usize,
    /// Expression emitter reference
    expr_emitter: ExprEmitter<'a>,
}

impl<'a> StmtEmitter<'a> {
    /// Create a new statement emitter.
    pub fn new(analysis: &'a AnalysisResult) -> Self {
        Self {
            output: String::new(),
            indent: 0,
            expr_emitter: ExprEmitter::new(analysis),
        }
    }

    /// Emit a statement.
    #[allow(unused)]
    pub fn emit_stmt(&mut self, stmt: &str) {
        self.push_indent();
        self.push(stmt);
        self.push_line(";");
    }

    /// Get the output.
    #[must_use]
    pub fn into_output(self) -> String {
        self.output
    }

    fn push(&mut self, s: &str) {
        self.output.push_str(s);
    }

    fn push_line(&mut self, s: &str) {
        self.output.push_str(s);
        self.output.push('\n');
    }

    fn push_indent(&mut self) {
        for _ in 0..self.indent {
            self.output.push_str("    ");
        }
    }
}

