//! # Rust Emitter
//!
//! Core transpilation from TypeScript to Rust source.

use crate::{parser::SourceFile, analyzer::AnalysisResult};
use crate::codegen::{GeneratedModule, Import, CodegenOptions};

/// Options for code emission.
#[derive(Debug, Clone, Default)]
pub struct EmitOptions {
    /// Generate debug info
    pub source_map: bool,
    /// Pretty print output
    pub pretty: bool,
}

/// Emits Rust code from TypeScript source.
#[derive(Debug)]
pub struct RustEmitter<'a> {
    /// Source file being transpiled
    source: &'a SourceFile,
    /// Analysis results
    analysis: &'a AnalysisResult,
    /// Imports needed by this module
    imports: Vec<Import>,
    /// Output buffer
    output: String,
    /// Current indentation level
    indent: usize,
    /// Generation options
    #[allow(unused)]
    options: CodegenOptions,
}

impl<'a> RustEmitter<'a> {
    /// Create a new emitter.
    #[must_use]
    pub fn new(source: &'a SourceFile, analysis: &'a AnalysisResult) -> Self {
        Self {
            source,
            analysis,
            imports: Vec::new(),
            output: String::new(),
            indent: 0,
            options: CodegenOptions::default(),
        }
    }

    /// Emit the complete module.
    ///
    /// # Errors
    /// Returns an error if code generation fails.
    pub fn emit(mut self) -> crate::Result<GeneratedModule> {
        self.write_header();
        self.write_types();
        self.write_functions();
        self.write_footer();

        let name = self.source.path.file_stem()
            .and_then(std::ffi::OsStr::to_str)
            .unwrap_or("module")
            .to_string();

        Ok(GeneratedModule {
            name,
            source: self.output,
            imports: self.imports,
            types: Vec::new(),
            functions: Vec::new(),
        })
    }

    /// Write module header with imports.
    fn write_header(&mut self) {
        self.push_line("//! Generated from Rune source");
        self.push_line("");
        self.push_line("use std::collections::HashMap;");
        self.push_line("use std::fmt::{self, Write};");
        self.push_line("");

        // Add protocol imports for app crate
        if self.source.path.to_string_lossy().contains("/app/src/") {
            self.push_line("use protocol::{AppState, Filter, Task};");
            self.push_line("");
        }
    }

    /// Write type definitions.
    fn write_types(&mut self) {
        for (_, info) in self.analysis.types.iter() {
            match info {
                crate::analyzer::TypeInfo::Struct(s) => {
                    self.push_line("");
                    self.push_line(&s.to_rust());
                    self.push_line("");
                }
                crate::analyzer::TypeInfo::Enum(e) => {
                    self.push_line("");
                    self.push_line(&e.to_rust());
                    self.push_line("");
                }
                _ => {}
            }
        }
    }

    /// Write function definitions.
    fn write_functions(&mut self) {
        for (name, info) in self.analysis.types.iter() {
            if let crate::analyzer::TypeInfo::Function(func) = info {
                self.emit_function(name, func);
            }
        }
    }

    /// Emit a single function definition.
    fn emit_function(&mut self, name: &str, func: &crate::analyzer::FunctionInfo) {
        let rust_name = to_snake_case(name);
        let async_prefix = if func.is_async { "async " } else { "" };

        // Build parameter list
        let params: Vec<String> = func.params.iter()
            .map(|(n, t)| format!("{}: {}", to_snake_case(n), t.to_rust_type()))
            .collect();
        let params_str = params.join(", ");

        // Build return type
        let return_type = func.return_type.to_rust_type();

        self.push_line("");
        self.push_line(&format!("/// Function: {name}"));

        if func.is_async {
            self.push_line(&format!(
                "{async_prefix}pub fn {rust_name}({params_str}) -> impl Future<Output = {return_type}> + '_ {{"
            ));
        } else {
            self.push_line(&format!("pub fn {rust_name}({params_str}) -> {return_type} {{"));
        }

        self.indent += 1;

        // Generate function body based on the source
        self.generate_function_body(name);

        self.indent -= 1;
        self.push_line("}");
        self.push_line("");
    }

    /// Generate function body from source.
    #[allow(clippy::too_many_lines)]
    fn generate_function_body(&mut self, _name: &str) {
        // Find the function in the source text
        let source = &self.source.source;

        for line in source.lines() {
            let trimmed = line.trim();

            // Skip empty lines and comments
            if trimmed.is_empty() || trimmed.starts_with("//") {
                self.push_line("");
                continue;
            }

            // Find function body
            if trimmed.contains("function ") && trimmed.contains(_name) {
                let body_start = trimmed.find('{').or_else(|| trimmed.find("=>"));
                if let Some(start) = body_start {
                    let body = &trimmed[start + 1..];
                    if body.contains('}') {
                        let cleaned = body.trim_end_matches('}').trim_start_matches('{').trim();
                        self.translate_line(&format!("    {cleaned}"));
                    }
                }
            }
        }
    }

    /// Translate a TypeScript line to Rust.
    fn translate_line(&mut self, line: &str) {
        let trimmed = line.trim();

        if trimmed.is_empty() {
            self.push_line("");
            return;
        }

        // Variable declarations
        if trimmed.starts_with("const ") || trimmed.starts_with("let ") {
            self.translate_binding(trimmed);
            return;
        }

        // Return statements
        if let Some(expr) = trimmed.strip_prefix("return ") {
            let expr = expr.trim_end_matches(';');
            self.push_indent();
            self.push_line(&format!("return {};", self.translate_expr(expr)));
            return;
        }

        // If statements
        if trimmed.starts_with("if ") {
            self.translate_if(trimmed);
            return;
        }

        // For loops
        if trimmed.starts_with("for ") {
            self.translate_for(trimmed);
            return;
        }

        // Switch statements
        if trimmed.starts_with("switch ") {
            self.translate_switch(trimmed);
            return;
        }

        // While loops
        if trimmed.starts_with("while ") {
            self.translate_while(trimmed);
            return;
        }

        // Default: function calls in expression context
        self.push_indent();
        self.push_line(&format!(
            "{};",
            self.translate_expr(trimmed.trim_end_matches(';'))
        ));
    }

    /// Translate a variable binding.
    fn translate_binding(&mut self, line: &str) {
        let (keyword, rest) = if let Some(r) = line.strip_prefix("const ") {
            ("let", r)
        } else {
            ("let mut", line.strip_prefix("let ").unwrap_or(line))
        };

        let rest = rest.trim_end_matches(';');

        if let Some(eq_pos) = rest.find(" = ") {
            let name_type = &rest[..eq_pos];
            let value = &rest[eq_pos + 3..];

            if let Some(colon_pos) = name_type.find(": ") {
                let name = name_type[..colon_pos].trim();
                let type_hint = name_type[colon_pos + 2..].trim();
                self.push_indent();
                self.push_line(&format!(
                    "{keyword} {name}: {} = {};",
                    self.parse_type_hint(type_hint),
                    self.translate_expr(value)
                ));
            } else {
                let name = name_type.trim();
                self.push_indent();
                self.push_line(&format!(
                    "{keyword} {name} = {};",
                    self.translate_expr(value)
                ));
            }
        }
    }

    /// Translate an if statement.
    fn translate_if(&mut self, line: &str) {
        let rest = line.strip_prefix("if ").unwrap();

        if let Some(brace_pos) = rest.find('{') {
            let condition = rest[..brace_pos].trim();
            self.push_indent();
            self.push_line(&format!("if {} {{", self.translate_condition(condition)));
            self.indent += 1;
        }
    }

    /// Translate a for loop.
    fn translate_for(&mut self, line: &str) {
        if line.contains(" of ") {
            // Iterator-based for loop
            if let Some(of_pos) = line.find(" of ") {
                let binding = &line[5..of_pos].trim();
                let array = rest_until(line, of_pos + 4, ')');
                let var_name = binding
                    .replace("const ", "")
                    .replace("let ", "")
                    .trim()
                    .to_string();

                self.push_indent();
                self.push_line(&format!("for {var_name} in {} {{", self.translate_expr(array)));
                self.indent += 1;
            }
        } else if line.contains(" = ") {
            // C-style for loop
            let rest = line.strip_prefix("for ").unwrap().trim_start_matches('(').trim_end_matches(')');
            self.push_indent();
            self.push_line(&format!(
                "for {} {{",
                self.translate_expr(rest.trim_end_matches(';'))
            ));
            self.indent += 1;
        }
    }

    /// Translate a switch statement.
    fn translate_switch(&mut self, line: &str) {
        let rest = line.strip_prefix("switch ").unwrap();

        if let Some(brace_pos) = rest.find('{') {
            let expr = rest[..brace_pos].trim();
            self.push_indent();
            self.push_line(&format!("match {} {{", self.translate_expr(expr)));
            self.indent += 1;
        }
    }

    /// Translate a while loop.
    fn translate_while(&mut self, line: &str) {
        let rest = line.strip_prefix("while ").unwrap();

        if let Some(brace_pos) = rest.find('{') {
            let condition = rest[..brace_pos].trim();
            self.push_indent();
            self.push_line(&format!("while {} {{", self.translate_condition(condition)));
            self.indent += 1;
        }
    }

    /// Translate an expression.
    #[allow(clippy::too_many_lines)]
    fn translate_expr(&self, expr: &str) -> String {
        let expr = expr.trim();

        // String literals - keep as-is
        if expr.starts_with('"') || expr.starts_with('\'') {
            return expr.to_string();
        }

        // Number literals - keep as-is
        if expr.parse::<f64>().is_ok() {
            return expr.to_string();
        }

        // Boolean literals
        if expr == "true" || expr == "false" {
            return expr.to_string();
        }

        // Ternary operator
        if expr.contains(" ? ") {
            return self.translate_ternary(expr);
        }

        // Binary operations
        if let Some(op) = Self::find_binary_op(expr) {
            return self.translate_binary_op(expr, op);
        }

        // Function calls
        if expr.contains('(') {
            return self.translate_call(expr);
        }

        // Property access
        if expr.contains('.') && !expr.contains('(') {
            return Self::translate_property_access(expr);
        }

        // Array literals
        if expr.starts_with('[') {
            return self.translate_array_literal(expr);
        }

        // Object literals
        if expr.starts_with('{') {
            return self.translate_object_literal(expr);
        }

        // Simple identifier
        to_snake_case(expr)
    }

    /// Translate a ternary expression.
    fn translate_ternary(&self, expr: &str) -> String {
        // Find the ? and : positions
        let question_pos = expr.find(" ? ")
            .unwrap_or_else(|| expr.find("?(").unwrap_or(0));
        let colon_pos = expr.rfind(" : ")
            .unwrap_or_else(|| expr.rfind(":(").unwrap_or(0));

        if colon_pos > question_pos {
            let condition = self.translate_condition(&expr[..question_pos]);
            let then_expr = expr[question_pos + 3..colon_pos].trim();
            let else_expr = expr[colon_pos + 3..]
                .trim_end_matches(';')
                .trim_end_matches(')');

            return format!(
                "if {} {{ {} }} else {{ {} }}",
                condition,
                self.translate_expr(then_expr),
                self.translate_expr(else_expr)
            );
        }

        expr.to_string()
    }

    /// Find binary operator in expression.
    fn find_binary_op(expr: &str) -> Option<&'static str> {
        const OPS: &[&str] = &[
            "+=", "-=", "*=", "/=", "===", "!==", "==", "!=",
            "<=", ">=", "&&", "||", "+", "-", "*", "/", "%",
            ">", "<", "|", "&", "^",
        ];

        OPS.iter().find(|&&op| expr.contains(op)).copied()
    }

    /// Translate a binary operation.
    fn translate_binary_op(&self, expr: &str, op: &str) -> String {
        let parts: Vec<&str> = expr.split(op).collect();

        if parts.len() == 2 {
            let left = parts[0].trim();
            let right = parts[1].trim();

            let rust_op = match op {
                "===" | "==" => "==",
                "!==" | "!=" => "!=",
                "&&" => "&&",
                "||" => "||",
                "+" | "-" | "*" | "/" | "%" | "|" | "&" | "^" => op,
                "<" | ">" | "<=" | ">=" => op,
                _ => op,
            };

            return format!(
                "({} {rust_op} {})",
                self.translate_expr(left),
                self.translate_expr(right)
            );
        }

        expr.to_string()
    }

    /// Translate a function call.
    fn translate_call(&self, expr: &str) -> String {
        if let Some(paren_pos) = expr.find('(') {
            let func = &expr[..paren_pos];
            let args = expr[paren_pos + 1..]
                .trim_end_matches(')')
                .trim_end_matches(';');

            let rust_func = to_snake_case(func);
            let translated_args: Vec<String> = args.split(',')
                .map(|a| self.translate_expr(a.trim()))
                .collect();

            return format!("{rust_func}({})", translated_args.join(", "));
        }

        to_snake_case(expr)
    }

    /// Translate property access.
    fn translate_property_access(expr: &str) -> String {
        expr.split('.')
            .map(to_snake_case)
            .collect::<Vec<_>>()
            .join(".")
    }

    /// Translate an array literal.
    fn translate_array_literal(&self, expr: &str) -> String {
        let inner = expr.trim_start_matches('[').trim_end_matches(']');
        let elements: Vec<String> = inner
            .split(',')
            .map(|e| self.translate_expr(e.trim()))
            .collect();

        format!("vec![{}]", elements.join(", "))
    }

    /// Translate an object literal.
    fn translate_object_literal(&self, expr: &str) -> String {
        let inner = expr.trim_start_matches('{').trim_end_matches('}');
        let fields: Vec<String> = inner
            .split(',')
            .filter_map(|f| {
                let f = f.trim();
                if f.is_empty() {
                    return None;
                }
                let parts: Vec<&str> = f.split(':').collect();
                if parts.len() == 2 {
                    let key = parts[0].trim();
                    let value = self.translate_expr(parts[1].trim());
                    return Some(format!("{key}: {value}"));
                }
                Some(f.to_string())
            })
            .collect();

        format!("{{ {} }}", fields.join(", "))
    }

    /// Translate a condition.
    fn translate_condition(&self, cond: &str) -> String {
        let cond = cond.trim();

        // Negation
        if let Some(inner) = cond.strip_prefix('!') {
            return format!("!{}", self.translate_condition(inner.trim()));
        }

        // Parentheses
        if cond.starts_with('(') && cond.ends_with(')') {
            let inner = &cond[1..cond.len() - 1];
            return format!("({})", self.translate_condition(inner));
        }

        self.translate_expr(cond)
    }

    /// Write module footer.
    fn write_footer(&mut self) {
        self.push_line("// End of generated code");
    }

    /// Parse a type hint string.
    #[allow(clippy::unused_self)]
    fn parse_type_hint(&self, hint: &str) -> String {
        match hint {
            "number" => "f64".to_string(),
            "string" => "String".to_string(),
            "boolean" => "bool".to_string(),
            "i32" | "integer" => "i32".to_string(),
            "usize" => "usize".to_string(),
            "void" | "undefined" => "()".to_string(),
            _ => hint.to_string(),
        }
    }

    fn push_line(&mut self, s: &str) {
        self.output.push_str(s);
        self.output.push('\n');
    }

    fn push_indent(&mut self) {
        for _ in 0..self.indent {
            self.output.push_str("    ");
        }
    }
}

/// Extract substring until a closing character.
fn rest_until(s: &str, start: usize, end: char) -> &str {
    if let Some(end_pos) = s[start..].find(end) {
        &s[start..start + end_pos]
    } else {
        &s[start..]
    }
}

/// Convert camelCase/snake_case to snake_case.
#[must_use]
pub fn to_snake_case(s: &str) -> String {
    let mut result = String::new();
    let chars: Vec<char> = s.chars().collect();

    for (i, c) in chars.iter().enumerate() {
        if c.is_uppercase() {
            if i > 0 && !chars[i - 1].is_uppercase() {
                result.push('_');
            }
            result.push(c.to_ascii_lowercase());
        } else if *c == '-' {
            result.push('_');
        } else {
            result.push(*c);
        }
    }

    // Handle consecutive uppercase (e.g., "URLParser" -> "url_parser")
    let mut final_result = String::new();
    for (i, c) in result.chars().enumerate() {
        if i > 0 && i < result.len() - 1 {
            let prev = result.chars().nth(i - 1);
            let next = result.chars().nth(i + 1);
            if c.is_uppercase() && prev.is_some_and(|p| !p.is_uppercase()) {
                final_result.push('_');
            }
            if c.is_uppercase() && next.is_some_and(|n| n.is_uppercase()) {
                // keep as is
            } else if c.is_uppercase() {
                final_result.push('_');
            }
        }
        final_result.push(c.to_ascii_lowercase());
    }

    final_result.trim_matches('_').to_string()
}

//! # JSX Transpiler
//!
//! Transpiles JSX/TSX syntax to Rust widget construction patterns.

use std::fmt::Write as FmtWrite;

/// Widget library to transpile to.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum WidgetLibrary {
    /// Ratatui TUI library
    Ratatui,
    /// Iced GUI library
    Iced,
}

impl Default for WidgetLibrary {
    fn default() -> Self {
        Self::Ratatui
    }
}

/// JSX transpiler for Rust UI libraries.
#[derive(Debug)]
pub struct JsxTranspiler {
    /// Target widget library
    library: WidgetLibrary,
}

impl JsxTranspiler {
    /// Create a new JSX transpiler.
    #[must_use]
    pub const fn new(library: WidgetLibrary) -> Self {
        Self { library }
    }

    /// Transpile a JSX element.
    #[must_use]
    pub fn transpile_element(&self, elem: &str) -> String {
        match self.library {
            WidgetLibrary::Ratatui => self.transpile_ratatui(elem),
            WidgetLibrary::Iced => self.transpile_iced(elem),
        }
    }

    /// Transpile to Ratatui widget construction.
    fn transpile_ratatui(&self, elem: &str) -> String {
        let elem = elem.trim();
        let (tag, _rest) = if let Some(space) = elem.find(' ') {
            (&elem[..space], Some(&elem[space..]))
        } else if let Some(gt) = elem.find('>') {
            (&elem[..gt], Some(&elem[gt..]))
        } else {
            (elem.trim_end_matches('/'), None)
        };

        let widget = match tag {
            "Block" => "Block::default()",
            "List" => "List::new(items)",
            "ListItem" => "ListItem::new(text)",
            "Paragraph" | "Text" => "Paragraph::new(text)",
            "Button" => "Button::default()",
            "Input" => "Paragraph::new(text)", // Simplified
            "VStack" => "Column::new()",
            "HStack" => "Row::new()",
            _ => &format!("{tag}::default()"),
        };

        format!("{widget}.block()")
    }

    /// Transpile to Iced widget construction.
    fn transpile_iced(&self, elem: &str) -> String {
        let elem = elem.trim();
        let (tag, _rest) = if let Some(space) = elem.find(' ') {
            (&elem[..space], Some(&elem[space..]))
        } else {
            (elem.trim_end_matches('/'), None)
        };

        match tag {
            "Button" => "button::Button::new(text)",
            "Text" => "text::Text::new(text)",
            "Column" => "Column::new()",
            "Row" => "Row::new()",
            "Container" => "Container::new(content)",
            _ => format!("{tag}::new()"),
        }
    }

    /// Transpile an element with props.
    #[must_use]
    pub fn transpile_with_props(&self, elem: &str, props: &[(&str, &str)]) -> String {
        let base = self.transpile_element(elem);
        let mut result = base;

        for (key, value) in props {
            let _ = write!(result, ".{key}({value})");
        }

        result
    }

    /// Extract props from JSX attributes.
    #[must_use]
    pub fn extract_props(&self, attrs: &str) -> Vec<(&str, &str)> {
        let attrs = attrs.trim();
        if attrs.is_empty() {
            return Vec::new();
        }

        attrs
            .split_whitespace()
            .filter_map(|attr| {
                let parts: Vec<&str> = attr.split('=').collect();
                if parts.len() == 2 {
                    Some((parts[0], parts[1].trim_matches('"').trim_matches('\'')))
                } else {
                    None
                }
            })
            .collect()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_basic_element() {
        let transpiler = JsxTranspiler::new(WidgetLibrary::Ratatui);
        let result = transpiler.transpile_element("Block");
        assert!(result.contains("Block"));
    }

    #[test]
    fn test_props_extraction() {
        let transpiler = JsxTranspiler::new(WidgetLibrary::Ratatui);
        let props = transpiler.extract_props(r#"title="Hello" borders="single"#);
        assert_eq!(props.len(), 2);
        assert_eq!(props[0], ("title", "Hello"));
    }
}

//! # Source File Handling
//!
//! Manages source file parsing.

use std::fs;
use std::path::{Path, PathBuf};
use crate::{ParseError, Result};

/// Kind of source file.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum SourceKind {
    /// Standard TypeScript file (.r.ts)
    TypeScript,
    /// TSX file (.r.tsx)
    Tsx,
}

/// A parsed Rune source file.
#[derive(Debug, Clone)]
pub struct SourceFile {
    /// File path
    pub path: PathBuf,
    /// Kind of source file
    pub kind: SourceKind,
    /// Raw source text
    pub source: String,
    /// Module name for display
    pub name: String,
    /// Whether parsing was successful
    pub valid: bool,
    /// Parse errors if any
    pub errors: Vec<ParseError>,
}

impl SourceFile {
    /// Parse a source file from a path.
    ///
    /// # Errors
    /// Returns an error if the file cannot be read.
    pub fn parse(path: &Path, kind: SourceKind) -> Result<Self> {
        if !path.exists() {
            return Err(ParseError::NotFound(path.display().to_string()).into());
        }

        let source = fs::read_to_string(path)?;

        let name = path
            .file_stem()
            .and_then(std::ffi::OsStr::to_str)
            .unwrap_or("module")
            .to_string();

        let errors = Self::validate_syntax(&source);

        Ok(Self {
            path: path.to_path_buf(),
            kind,
            source,
            name,
            valid: errors.is_empty(),
            errors,
        })
    }

    /// Validate basic syntax.
    fn validate_syntax(source: &str) -> Vec<ParseError> {
        let mut errors = Vec::new();
        let mut depth = SyntaxDepth::default();

        let mut in_string = false;
        let mut string_char = '"';
        let mut line = 1u32;

        let chars: Vec<char> = source.chars().collect();
        let mut i = 0;

        while i < chars.len() {
            let c = chars[i];

            if c == '\n' {
                line += 1;
            }

            // Handle string literals
            if !in_string && (c == '"' || c == '\'') {
                in_string = true;
                string_char = c;
            } else if in_string && c == string_char && !escaped(&chars, i) {
                in_string = false;
            } else if !in_string {
                match c {
                    '{' => depth.brace += 1,
                    '}' => {
                        depth.brace -= 1;
                        if depth.brace < 0 {
                            errors.push(ParseError::Parse(format!(
                                "Unexpected closing brace at line {line}"
                            )));
                            depth.brace = 0;
                        }
                    }
                    '(' => depth.paren += 1,
                    ')' => {
                        depth.paren -= 1;
                        if depth.paren < 0 {
                            errors.push(ParseError::Parse(format!(
                                "Unexpected closing parenthesis at line {line}"
                            )));
                            depth.paren = 0;
                        }
                    }
                    '[' => depth.bracket += 1,
                    ']' => {
                        depth.bracket -= 1;
                        if depth.bracket < 0 {
                            errors.push(ParseError::Parse(format!(
                                "Unexpected closing bracket at line {line}"
                            )));
                            depth.bracket = 0;
                        }
                    }
                    _ => {}
                }
            }

            i += 1;
        }

        if depth.brace != 0 {
            errors.push(ParseError::Parse("Unclosed brace(s) at end of file".into()));
        }
        if depth.paren != 0 {
            errors.push(ParseError::Parse("Unclosed parenthesis(es) at end of file".into()));
        }
        if depth.bracket != 0 {
            errors.push(ParseError::Parse("Unclosed bracket(s) at end of file".into()));
        }

        errors
    }

    /// Get line and column from byte offset.
    #[must_use]
    pub fn location_from_offset(&self, offset: u32) -> (u32, u32) {
        let mut line = 1u32;
        let mut col = 1u32;

        for (pos, c) in self.source.chars().enumerate() {
            if pos as u32 >= offset {
                break;
            }
            if c == '\n' {
                line += 1;
                col = 1;
            } else {
                col += 1;
            }
        }

        (line, col)
    }

    /// Get the module name.
    #[must_use]
    pub fn module_name(&self) -> &str {
        &self.name
    }

    /// Check if this is a TSX file.
    #[must_use]
    pub fn is_tsx(&self) -> bool {
        self.kind == SourceKind::Tsx
    }
}

/// Track nested syntax depth.
#[derive(Default)]
struct SyntaxDepth {
    brace: i32,
    paren: i32,
    bracket: i32,
}

/// Check if a character is escaped.
fn escaped(chars: &[char], pos: usize) -> bool {
    let mut count = 0;
    let mut i = pos;
    while i > 0 {
        i -= 1;
        if chars[i] == '\\' {
            count += 1;
        } else {
            break;
        }
    }
    count % 2 == 1
}

/// Parse diagnostics module.
pub mod diagnostics {
    use crate::ParseError;

    /// Accumulated parse diagnostics.
    #[derive(Debug, Default)]
    pub struct ParseDiagnostics {
        errors: Vec<ParseError>,
    }

    impl ParseDiagnostics {
        /// Create a new diagnostics collector.
        #[must_use]
        pub const fn new() -> Self {
            Self { errors: Vec::new() }
        }

        /// Add an error.
        pub fn add_error(&mut self, err: ParseError) {
            self.errors.push(err);
        }

        /// Check if there are any errors.
        #[must_use]
        pub const fn has_errors(&self) -> bool {
            !self.errors.is_empty()
        }

        /// Get all errors.
        #[must_use]
        pub fn errors(&self) -> &[ParseError] {
            &self.errors
        }

        /// Take all errors, leaving an empty collector.
        pub fn take_errors(&mut self) -> Vec<ParseError> {
            std::mem::take(&mut self.errors)
        }
    }

    impl std::fmt::Display for ParseDiagnostics {
        fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
            write!(f, "Parse errors: {}", self.errors.len())
        }
    }
}

//! # Build Driver
//!
//! Main compilation orchestration.

use std::path::PathBuf;
use std::process::Command as ProcCommand;
use crate::{Result, parser, analyzer, codegen};
use super::config::RuneConfig;
use super::cache::CacheManager;

/// Build mode.
#[derive(Debug, Clone, Copy, Default)]
pub enum BuildMode {
    /// Development with hot reload
    #[default]
    Dev,
    /// Release build
    Release,
}

/// Options for building.
#[derive(Debug, Clone)]
pub struct BuildOptions {
    /// Mode to build in
    pub mode: BuildMode,
    /// Working directory
    pub workspace: PathBuf,
    /// Target crate name
    pub target_crate: Option<String>,
    /// Config file path
    pub config: Option<PathBuf>,
    /// File to transpile (for transpile command)
    pub transpile_file: Option<PathBuf>,
    /// Verbose output
    pub verbose: bool,
}

impl BuildOptions {
    /// Create new options.
    #[must_use]
    pub const fn new(workspace: PathBuf) -> Self {
        Self {
            mode: BuildMode::Dev,
            workspace,
            target_crate: None,
            config: None,
            transpile_file: None,
            verbose: false,
        }
    }

    /// Set development mode.
    #[must_use]
    pub const fn dev(mut self) -> Self {
        self.mode = BuildMode::Dev;
        self
    }

    /// Set release mode.
    #[must_use]
    pub const fn release(mut self) -> Self {
        self.mode = BuildMode::Release;
        self
    }
}

/// Main build driver.
pub struct BuildDriver {
    options: BuildOptions,
    config: RuneConfig,
    cache: CacheManager,
}

impl BuildDriver {
    /// Create a new build driver.
    ///
    /// # Errors
    /// Returns an error if configuration or cache cannot be initialized.
    pub fn new(options: BuildOptions) -> Result<Self> {
        let config_path = options.config.clone()
            .or_else(|| Some(options.workspace.join("rune.toml")));

        let config = if let Some(ref path) = config_path {
            if path.exists() {
                RuneConfig::load(path)?
            } else {
                RuneConfig::default()
            }
        } else {
            RuneConfig::default()
        };

        let cache = CacheManager::new(&options.workspace)?;

        Ok(Self {
            options,
            config,
            cache,
        })
    }

    /// Run in development mode with hot reload.
    ///
    /// # Errors
    /// Returns an error if build fails.
    pub fn dev(&mut self) -> Result<()> {
        if self.options.verbose {
            println!("Running in development mode with hot reload...");
        }

        let sources = self.find_sources()?;
        if self.options.verbose {
            println!("Found {} Rune source files", sources.len());
        }

        let parsed = Self::parse_sources(&sources)?;
        let analyses = Self::analyze_sources(&parsed)?;
        let generated = self.generate_code(&parsed, &analyses)?;
        self.write_generated(&generated)?;
        self.build_crate(false)?;
        self.setup_hot_reload()?;

        if self.options.verbose {
            println!("Development build complete. Dylib ready.");
        }

        Ok(())
    }

    /// Run in release mode.
    ///
    /// # Errors
    /// Returns an error if build fails.
    pub fn build(&mut self) -> Result<()> {
        if self.options.verbose {
            println!("Running in release mode...");
        }

        let sources = self.find_sources()?;
        let parsed = Self::parse_sources(&sources)?;
        let analyses = Self::analyze_sources(&parsed)?;
        let generated = self.generate_code(&parsed, &analyses)?;
        self.write_generated(&generated)?;
        self.build_crate(true)?;

        if self.options.verbose {
            println!("Release build complete.");
        }

        Ok(())
    }

    /// Type check only.
    ///
    /// # Errors
    /// Returns an error if analysis fails.
    pub fn check(&mut self) -> Result<()> {
        let sources = self.find_sources()?;
        let parsed = Self::parse_sources(&sources)?;
        let analyses = Self::analyze_sources(&parsed)?;

        for analysis in &analyses {
            for warning in &analysis.warnings {
                println!("warning: {} at {}", warning.message, warning.location);
            }
        }

        println!("Type check passed for {} files.", parsed.len());
        Ok(())
    }

    /// Transpile a single file to stdout.
    ///
    /// # Errors
    /// Returns an error if transpilation fails.
    pub fn transpile(&mut self) -> Result<()> {
        let file = self.options.transpile_file.as_ref()
            .ok_or_else(|| crate::RuneError::Codegen("No file specified".into()))?;

        let source = parser::parse_file(file)?;
        let analysis = analyzer::analyze(&source)?;
        let module = codegen::generate(&source, &analysis)?;

        println!("{}", module.source);
        Ok(())
    }

    /// Initialize a new project.
    ///
    /// # Errors
    /// Returns an error if project creation fails.
    #[allow(clippy::too_many_lines)]
    pub fn init(&mut self) -> Result<()> {
        let project_name = self.config.project.name.clone();
        let target_crate = self.config.build.target_crate.clone();

        let base = self.options.workspace.join("crates").join(&target_crate);
        std::fs::create_dir_all(base.join("src/native"))?;
        std::fs::create_dir_all(base.join("src/views"))?;

        let cargo = format!(r#"[package]
name = "{target_crate}"
version = "0.1.0"
edition = "2021"

[lib]
name = "{target_crate}"
path = "src/lib.rs"

[dependencies]
protocol = {{ path = "../protocol" }}
ratatui = "0.26"

[build-dependencies]
rune = {{ path = "../../.." }}
"#);

        std::fs::write(base.join("Cargo.toml"), cargo)?;

        let lib = r#"mod native;

pub struct AppState {
    pub tasks: Vec<Task>,
}

#[derive(Clone)]
pub struct Task {
    pub id: i32,
    pub title: String,
    pub done: bool,
}

#[no_mangle]
pub extern "C" fn create_app() -> *mut dyn protocol::App {
    Box::into_raw(Box::new(AppImpl))
}

struct AppImpl;

impl protocol::App for AppImpl {
    fn update(&mut self, _state: &mut AppState) {}
    fn render(&self, _term: &mut impl ratatui::backend::Backend, _state: &AppState) {}
}
"#;

        std::fs::write(base.join("src/lib.rs"), lib)?;

        let main_ts = "export function update(state: AppState): void {}\n\
export function render(state: AppState): void {}\n";

        std::fs::write(base.join("src/main.r.ts"), main_ts)?;

        let state_ts = "export type Task = { id: number; title: string; done: boolean };\n\
export type AppState = { tasks: Task[]; selected: number };\n";

        std::fs::write(base.join("src/state.r.ts"), state_ts)?;

        let native_mod = "pub mod fast_math;\n";
        std::fs::write(base.join("src/native/mod.rs"), native_mod)?;

        let fast_math = "pub fn fast_sqrt(x: f64) -> f64 { x.sqrt() }\n";
        std::fs::write(base.join("src/native/fast_math.rs"), fast_math)?;

        println!("Initialized Rune project: {project_name}");
        println!("Created structure in crates/{target_crate}/");

        Ok(())
    }

    fn find_sources(&self) -> Result<Vec<PathBuf>> {
        let src_dir = self.options.workspace
            .join("crates")
            .join(&self.config.build.target_crate)
            .join("src");

        parser::scan_directory(&src_dir)
    }

    fn parse_sources(sources: &[PathBuf]) -> Result<Vec<parser::SourceFile>> {
        sources.iter().map(parser::parse_file).collect()
    }

    fn analyze_sources(sources: &[parser::SourceFile]) -> Result<Vec<analyzer::AnalysisResult>> {
        sources.iter().map(analyzer::analyze).collect()
    }

    fn generate_code(
        &self,
        sources: &[parser::SourceFile],
        analyses: &[analyzer::AnalysisResult],
    ) -> Result<Vec<codegen::GeneratedModule>> {
        sources.iter()
            .zip(analyses.iter())
            .map(|(s, a)| codegen::generate(s, a))
            .collect()
    }

    fn write_generated(&self, modules: &[codegen::GeneratedModule]) -> Result<()> {
        let cache_dir = self.cache.generated_dir();

        for module in modules {
            let rel_path = module.name.replace(".r", "");
            let out_path = cache_dir.join(format!("{rel_path}.rs"));
            std::fs::create_dir_all(out_path.parent().unwrap())?;
            std::fs::write(&out_path, &module.source)?;
        }

        Ok(())
    }

    fn build_crate(&self, release: bool) -> Result<()> {
        let manifest = self.cache.generated_cargo_toml();
        let mut cmd = ProcCommand::new("cargo");
        cmd.arg("build");
        if release {
            cmd.arg("--release");
        }
        cmd.arg("--manifest-path").arg(&manifest);

        if !self.options.verbose {
            cmd.stdout(std::process::Stdio::piped());
            cmd.stderr(std::process::Stdio::piped());
        }

        let output = cmd.output()
            .map_err(|e| crate::RuneError::Cargo(e.to_string()))?;

        if !output.status.success() {
            let stderr = String::from_utf8_lossy(&output.stderr);
            return Err(crate::RuneError::Cargo(stderr.to_string()));
        }

        Ok(())
    }

    #[allow(clippy::unnecessary_wraps)]
    fn setup_hot_reload(&self) -> Result<()> {
        let hot_dir = self.options.workspace.join("target/hot");
        std::fs::create_dir_all(&hot_dir)?;

        let profile = match self.options.mode {
            BuildMode::Dev => "debug",
            BuildMode::Release => "release",
        };

        let target_crate = &self.config.build.target_crate;
        let artifact_name = format!("lib{target_crate}.so");

        let artifact = self.options.workspace
            .join("target")
            .join(profile)
            .join(&artifact_name);

        if artifact.exists() {
            let timestamp = std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_millis();

            let safe_name = target_crate.replace('-', "_");
            let hot_name = format!("{safe_name}_{timestamp}.so");
            let hot_path = hot_dir.join(&hot_name);

            std::fs::copy(&artifact, &hot_path)?;

            let current = hot_dir.join(".current");
            if current.exists() {
                std::fs::remove_file(&current)?;
            }

            #[cfg(unix)]
            std::os::unix::fs::symlink(&hot_path, &current)?;

            #[cfg(windows)]
            std::os::windows::fs::symlink_file(&hot_path, &current)?;

            if self.options.verbose {
                println!("Hot reload ready: {hot_name}");
            }
        }

        Ok(())
    }
}

