//! # Hot Reload Module
//!
//! Provides hot reload functionality for dylib-based development.

mod watcher;
mod host;

pub use watcher::{DylibWatcher, ReloadEvent};
pub use host::HostSignaler;

use thiserror::Error;

/// Result type for reload operations.
pub type ReloadResult<T> = std::result::Result<T, ReloadError>;

/// Errors that can occur during hot reload.
#[derive(Error, Debug)]
pub enum ReloadError {
    #[error("Library error: {0}")]
    Library(String),

    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),

    #[error("Serialization error: {0}")]
    Serialization(String),
}

//! # Dylib Watcher
//!
//! Watches for changes in the hot reload directory and signals the host.

use std::path::{Path, PathBuf};
use std::sync::mpsc;
use std::time::Duration;
use notify::{Watcher, RecommendedWatcher, RecursiveMode, Event, EventKind};
use super::{ReloadResult, ReloadError};

/// Watches for dylib changes and notifies the host.
pub struct DylibWatcher {
    /// Watch directory
    watch_dir: PathBuf,
    /// Notify watcher
    watcher: RecommendedWatcher,
    /// Event receiver
    receiver: mpsc::Receiver<ReloadEvent>,
    /// Current dylib path
    current: Option<PathBuf>,
}

impl DylibWatcher {
    /// Create a new watcher.
    ///
    /// # Errors
    /// Returns an error if the watcher cannot be created.
    pub fn new(hot_dir: &Path) -> ReloadResult<Self> {
        let watch_dir = hot_dir.to_path_buf();
        let (tx, rx) = mpsc::channel();

        let watcher = notify::recommended_watcher(move |res: Result<Event, notify::Error>| {
            if let Ok(event) = res {
                if matches!(event.kind, EventKind::Create(_) | EventKind::Modify(_)) {
                    let _ = tx.send(ReloadEvent::Changed);
                }
            }
        })
        .map_err(|e| ReloadError::Library(e.to_string()))?;

        let mut watcher = watcher;
        watcher
            .watch(&watch_dir, RecursiveMode::NonRecursive)
            .map_err(|e| ReloadError::Library(e.to_string()))?;

        Ok(Self {
            watch_dir,
            watcher,
            receiver: rx,
            current: None,
        })
    }

    /// Poll for changes with timeout.
    #[must_use]
    pub fn poll(&mut self, timeout: Duration) -> Option<ReloadEvent> {
        match self.receiver.recv_timeout(timeout) {
            Ok(event) => Some(event),
            Err(mpsc::RecvTimeoutError::Timeout) => None,
            Err(mpsc::RecvTimeoutError::Disconnected) => Some(ReloadEvent::Disconnected),
        }
    }

    /// Check if the current dylib has changed.
    ///
    /// # Errors
    /// Returns an error if checking fails.
    pub fn check_current(&mut self) -> ReloadResult<Option<PathBuf>> {
        let current_link = self.watch_dir.join(".current");

        if !current_link.exists() {
            return Ok(None);
        }

        let target = std::fs::read_link(&current_link)?;

        if self.current.as_ref() != Some(&target) {
            self.current = Some(target.clone());
            return Ok(Some(target));
        }

        Ok(None)
    }

    /// Get the current dylib path.
    #[must_use]
    pub fn current_path(&self) -> Option<&Path> {
        self.current.as_deref()
    }

    /// Unwatch and clean up.
    #[allow(clippy::unused_self)]
    pub fn unwatch(self) {
        // Watcher is dropped here, which unregisters it
    }
}

/// Events from the watcher.
#[derive(Debug, Clone)]
pub enum ReloadEvent {
    /// A new dylib is available
    Changed,
    /// The channel was disconnected
    Disconnected,
}

//! # Host Signaler
//!
//! Signals the host process when a reload is needed.

use std::path::{Path, PathBuf};
use std::time::{SystemTime, UNIX_EPOCH};
use super::{ReloadResult, ReloadError};

/// Signals the host process about reload state.
pub struct HostSignaler {
    /// Hot directory path
    hot_dir: PathBuf,
    /// State file for protocol changes
    state_file: PathBuf,
}

impl HostSignaler {
    /// Create a new host signaler.
    ///
    /// # Errors
    /// Returns an error if initialization fails.
    pub fn new(hot_dir: &Path) -> ReloadResult<Self> {
        let hot_dir = hot_dir.to_path_buf();
        let state_file = hot_dir.join("restart_needed");
        Ok(Self {
            hot_dir,
            state_file,
        })
    }

    /// Signal that a reload is needed.
    ///
    /// # Errors
    /// Returns an error if signaling fails.
    #[allow(clippy::unwrap_used)]
    pub fn signal(&self) -> ReloadResult<()> {
        let timestamp = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap()
            .as_millis();

        let signal_file = self.hot_dir.join(format!("reload_{timestamp}.signal"));
        std::fs::write(&signal_file, "")?;
        Ok(())
    }

    /// Clear all reload signals.
    ///
    /// # Errors
    /// Returns an error if clearing fails.
    pub fn clear(&self) -> ReloadResult<()> {
        for entry in std::fs::read_dir(&self.hot_dir)? {
            let entry = entry?;
            let path = entry.path();
            if path.extension().is_some_and(|e| e == "signal") {
                std::fs::remove_file(path)?;
            }
        }
        Ok(())
    }

    /// Get the current dylib path.
    ///
    /// # Errors
    /// Returns an error if reading fails.
    pub fn current_dylib(&self) -> ReloadResult<Option<PathBuf>> {
        let current_link = self.hot_dir.join(".current");
        if current_link.exists() {
            Ok(Some(std::fs::read_link(current_link)?))
        } else {
            Ok(None)
        }
    }

    /// Check if a restart is needed (protocol changed).
    ///
    /// # Errors
    /// Returns an error if checking fails.
    pub fn should_restart(&self) -> ReloadResult<bool> {
        Ok(self.state_file.exists())
    }

    /// Mark that a restart is needed.
    ///
    /// # Errors
    /// Returns an error if marking fails.
    pub fn mark_restart_needed(&self) -> ReloadResult<()> {
        std::fs::write(&self.state_file, "")?;
        Ok(())
    }

    /// Clear the restart needed flag.
    ///
    /// # Errors
    /// Returns an error if clearing fails.
    pub fn clear_restart_needed(&self) -> ReloadResult<()> {
        if self.state_file.exists() {
            std::fs::remove_file(&self.state_file)?;
        }
        Ok(())
    }
}

