//! # Type Inference - Primitives
//!
//! Type inference for primitive types.

use super::{TypeInferrer, TypeInfo};

impl TypeInferrer {
    /// Infer type from a literal value.
    #[must_use]
    pub fn infer_literal(&self, literal: &str) -> TypeInfo {
        // Try integer
        if let Ok(n) = literal.parse::<i64>() {
            return TypeInfo::Integer(n);
        }

        // Try float
        if let Ok(f) = literal.parse::<f64>() {
            return TypeInfo::Float;
        }

        // String literal
        if literal.starts_with('"') || literal.starts_with('\'') {
            let content = &literal[1..literal.len() - 1];
            return TypeInfo::StringLiteral(content.to_string());
        }

        // Boolean
        if literal == "true" || literal == "false" {
            return TypeInfo::Boolean;
        }

        TypeInfo::Unknown
    }

    /// Infer type from binary operator.
    #[allow(dead_code)]
    #[must_use]
    pub fn infer_bin_expr_type(left: &TypeInfo, right: &TypeInfo) -> TypeInfo {
        use TypeInfo::*;

        match (left, right) {
            // Number + Number = Number
            (Integer(_), Integer(_)) => Integer(0),
            (Float, Integer(_)) | (Integer(_), Float) => Float,
            (Float, Float) => Float,
            // String + anything = String
            (String, _) | (StringLiteral(_), _) | (_, String) | (_, StringLiteral(_)) => String,
            // Boolean operations
            (Boolean, Boolean) => Boolean,
            _ => Unknown,
        }
    }
}

//! # Type Inference - TypeScript Types
//!
//! Type inference for TypeScript type annotations.

use super::{TypeInferrer, TypeInfo, StructInfo, EnumInfo, EnumVariant, FunctionInfo};

impl TypeInferrer {
    /// Parse a type annotation string.
    #[must_use]
    pub fn parse_type(&self, type_str: &str) -> TypeInfo {
        let trimmed = type_str.trim();

        // Handle primitive types
        match trimmed {
            "number" => TypeInfo::Float,
            "string" => TypeInfo::String,
            "boolean" => TypeInfo::Boolean,
            "void" | "undefined" => TypeInfo::Unknown,
            "null" => TypeInfo::Option(Box::new(TypeInfo::Unknown)),
            "any" | "unknown" => TypeInfo::Unknown,
            _ => {}
        }

        // Handle array types
        if let Some(inner) = trimmed.strip_prefix("number[]") {
            return TypeInfo::Array(Box::new(TypeInfo::Float));
        }
        if let Some(inner) = trimmed.strip_prefix("string[]") {
            return TypeInfo::Array(Box::new(TypeInfo::String));
        }
        if let Some(inner) = trimmed.strip_prefix("boolean[]") {
            return TypeInfo::Array(Box::new(TypeInfo::Boolean));
        }
        if trimmed.ends_with("[]") {
            let inner = &trimmed[..trimmed.len() - 2];
            return TypeInfo::Array(Box::new(self.parse_type(inner)));
        }

        // Handle union types
        if let Some(rest) = trimmed.strip_prefix("T | null") {
            return TypeInfo::Option(Box::new(self.parse_type(trimmed)));
        }
        if trimmed.contains(" | ") {
            let variants: Vec<&str> = trimmed.split(" | ").collect();
            if variants.len() == 2 && variants[1] == "null" {
                return TypeInfo::Option(Box::new(self.parse_type(variants[0])));
            }
            // Tagged union - need 'tag' field for enum detection
            let enum_info = self.parse_union_as_enum(trimmed);
            if let Some(info) = enum_info {
                return TypeInfo::Enum(info);
            }
        }

        // Handle Result pattern
        if trimmed.starts_with("Result<") {
            return self.parse_result_type(trimmed);
        }

        // Handle generic types
        if trimmed.ends_with('>') {
            return self.parse_generic_type(trimmed);
        }

        // Return as unknown
        TypeInfo::Unknown
    }

    /// Parse a union type as an enum if it has tag fields.
    fn parse_union_as_enum(&self, union: &str) -> Option<EnumInfo> {
        let variants: Vec<&str> = union.split(" | ").collect();

        let mut enum_variants = Vec::new();

        for variant in variants {
            let variant = variant.trim();
            if let Some(fields) = self.parse_tagged_variant(variant) {
                enum_variants.push(fields);
            } else {
                return None;
            }
        }

        Some(EnumInfo {
            name: "Union".to_string(),
            variants: enum_variants,
        })
    }

    /// Parse a tagged variant like `{ tag: "Name", ... }`.
    fn parse_tagged_variant(&self, variant: &str) -> Option<EnumVariant> {
        let variant = variant.trim();

        if !variant.starts_with('{') || !variant.ends_with('}') {
            return None;
        }

        let inner = &variant[1..variant.len() - 1];
        let mut tag = String::new();
        let mut fields = Vec::new();

        for field in inner.split(',') {
            let field = field.trim();
            if field.is_empty() {
                continue;
            }

            if let Some((key, value)) = field.split_once(':') {
                let key = key.trim();
                let value = value.trim();

                if key == "tag" && (value.starts_with('"') || value.starts_with('\'')) {
                    tag = value.trim_matches('"').trim_matches('\'').to_string();
                } else {
                    let type_info = self.parse_type(value);
                    fields.push((key.to_string(), type_info));
                }
            }
        }

        if !tag.is_empty() {
            Some(EnumVariant { tag, fields })
        } else {
            None
        }
    }

    /// Parse a Result type.
    fn parse_result_type(&self, result: &str) -> TypeInfo {
        if let Some(inner) = result.strip_prefix("Result<") {
            if let Some(end) = inner.strip_suffix('>') {
                if let Some((ok, err)) = end.split_once(", ") {
                    let ok_type = Box::new(self.parse_type(ok));
                    let err_type = Box::new(self.parse_type(err));
                    return TypeInfo::Result(ok_type, err_type);
                }
            }
        }
        TypeInfo::Unknown
    }

    /// Parse a generic type.
    fn parse_generic_type(&self, generic: &str) -> TypeInfo {
        if let Some(start) = generic.find('<') {
            let base = &generic[..start];
            let args_str = &generic[start + 1..generic.len() - 1];

            let args: Vec<TypeInfo> = args_str
                .split(',')
                .map(|s| self.parse_type(s.trim()))
                .collect();

            match base {
                "Array" | "Vec" => {
                    if let Some(inner) = args.first() {
                        return TypeInfo::Array(Box::new(inner.clone()));
                    }
                }
                "Option" => {
                    if let Some(inner) = args.first() {
                        return TypeInfo::Option(Box::new(inner.clone()));
                    }
                }
                "Result" => {
                    if args.len() == 2 {
                        return TypeInfo::Result(
                            Box::new(args[0].clone()),
                            Box::new(args[1].clone()),
                        );
                    }
                }
                "Map" => {
                    if args.len() == 2 {
                        return TypeInfo::Struct(StructInfo {
                            name: "MapPlaceholder".to_string(),
                            fields: Vec::new(),
                        });
                    }
                }
                _ => {
                    return TypeInfo::Generic(base.to_string());
                }
            }
        }

        TypeInfo::Unknown
    }

    /// Infer struct fields from an object literal.
    #[must_use]
    pub fn infer_struct_fields(&self, obj: &str) -> Vec<(String, TypeInfo)> {
        let obj = obj.trim();
        if !obj.starts_with('{') || !obj.ends_with('}') {
            return Vec::new();
        }

        let inner = &obj[1..obj.len() - 1];
        let mut fields = Vec::new();

        for field in inner.split(',') {
            let field = field.trim();
            if field.is_empty() {
                continue;
            }

            if let Some((key, value)) = field.split_once(':') {
                let key = key.trim();
                let value = value.trim();
                let type_info = self.infer_literal(value);
                fields.push((key.to_string(), type_info));
            }
        }

        fields
    }
}

